        # check next tag is title
        m = re.search(re.escape(tag) + r'\s*(<[^/][^>]*>)', html)
        if not m or not m.group(1).startswith('<title'):
            missing.append(tag[:60])
    print(p.name, 'svg count', len(svgs), 'missing title', len(missing))
    if missing:
        for m in missing[:3]: print('  ', m)
